module RefModule(
    input CLK,
    input D,
    input SET,
    input CLR,
    output reg Q,
    output reg Q_bar
);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CLK, posedge SET, posedge CLR or posedge dbg_halt) begin
    if (SET) begin
        Q <= 1'b1;
        Q_bar <= 1'b0;
    end else if (CLR) begin
        Q <= 1'b0;
        Q_bar <= 1'b1;
    end else begin
        Q <= D;
        Q_bar <= ~D;
    end
end

endmodule
